import { useEffect, useRef, useState } from 'react';

const COLORS = [
  'radial-gradient(circle at 50% 40%, #6366f1 0%, transparent 70%)',
  'radial-gradient(circle at 50% 40%, #f59e0b 0%, transparent 70%)',
  'radial-gradient(circle at 50% 40%, #10b981 0%, transparent 70%)',
];

export function useScrollGlow(sections = 3) {
  const [glow, setGlow] = useState(COLORS[0]);

  useEffect(() => {
    const onScroll = () => {
      const r = window.scrollY / (document.body.scrollHeight - window.innerHeight);
      setGlow(COLORS[Math.min(sections - 1, Math.floor(r * sections))]);
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, [sections]);

  return glow;
}

// Usage — place behind your page content
export function AmbientGlowBackground() {
  const glow = useScrollGlow(3);
  return (
    <div style={{
      position: 'fixed', inset: 0, pointerEvents: 'none',
      background: glow, opacity: 0.45, transition: 'background 1.2s', zIndex: -1,
    }} />
  );
}

