import { useEffect, useRef, useState } from 'react';

export function useInView(threshold = 0.2) {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const obs = new IntersectionObserver(
      ([e]) => { if (e.isIntersecting) { setVisible(true); obs.disconnect(); } },
      { threshold }
    );
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, [threshold]);
  return { ref, visible };
}

// Usage — wraps any grid of cards
export function StaggerReveal({ children, staggerMs = 80 }) {
  const { ref, visible } = useInView(0.15);
  return (
    <div ref={ref} style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(240px, 1fr))', gap: 16 }}>
      {React.Children.map(children, (child, i) => (
        <div style={{
          opacity: visible ? 1 : 0,
          transform: visible ? 'none' : 'translateY(24px)',
          transition: `opacity 0.5s ${i * staggerMs}ms, transform 0.5s ${i * staggerMs}ms`,
        }}>
          {child}
        </div>
      ))}
    </div>
  );
}

