import { useEffect, useRef } from 'react';

export function useParallax(speed = 0.3) {
  const ref = useRef(null);
  useEffect(() => {
    const onScroll = () => {
      if (!ref.current) return;
      const rect = ref.current.getBoundingClientRect();
      const offset = (rect.top + rect.height / 2 - window.innerHeight / 2) * speed;
      ref.current.style.transform = `translateY(${offset}px)`;
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    onScroll();
    return () => window.removeEventListener('scroll', onScroll);
  }, [speed]);
  return ref;
}

// Usage — wrap any element you want to parallax
export function ParallaxLayer({ children, speed = 0.25, style }) {
  const ref = useParallax(speed);
  return <div ref={ref} style={{ willChange: 'transform', ...style }}>{children}</div>;
}

// Stack example
export function HeroWithParallax() {
  return (
    <section style={{ position: 'relative', height: '100vh', overflow: 'hidden' }}>
      <ParallaxLayer speed={0.1} style={{ position: 'absolute', inset: 0, opacity: 0.3 }}>
        {/* background texture */}
      </ParallaxLayer>
      <ParallaxLayer speed={0.4} style={{ position: 'absolute', inset: 0 }}>
        {/* midground element */}
      </ParallaxLayer>
    </section>
  );
}

