import { useEffect, useRef, useState } from 'react';

export function useScrollClip() {
  const wrapRef = useRef(null);
  const [clip, setClip] = useState(100); // 100% hidden → 0% hidden

  useEffect(() => {
    const onScroll = () => {
      if (!wrapRef.current) return;
      const { top, height } = wrapRef.current.getBoundingClientRect();
      const ratio = Math.max(0, Math.min(1, (window.innerHeight - top) / (window.innerHeight + height)));
      setClip(Math.max(0, 100 - ratio * 160));
    };
    window.addEventListener('scroll', onScroll, { passive: true });
    onScroll();
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  return { wrapRef, clipPath: `inset(0 0 ${clip}% 0)` };
}

// Usage
export function ClipRevealGrid({ children }) {
  const { wrapRef, clipPath } = useScrollClip();
  return (
    <div ref={wrapRef} style={{ clipPath, transition: 'clip-path 0.12s linear' }}>
      {children}
    </div>
  );
}

