export function useCustomCursor(color = '#6366f1') {
  const ringRef = useRef(null);

  useEffect(() => {
    const ring = ringRef.current;
    if (!ring) return;
    const move = (e) => {
      ring.style.left = e.clientX + 'px';
      ring.style.top = e.clientY + 'px';
    };
    window.addEventListener('pointermove', move);
    document.body.style.cursor = 'none';
    return () => {
      window.removeEventListener('pointermove', move);
      document.body.style.cursor = '';
    };
  }, []);

  // Expand on link hover
  useEffect(() => {
    const expand = () => { if(ringRef.current) ringRef.current.style.width = ringRef.current.style.height = '36px'; };
    const shrink = () => { if(ringRef.current) ringRef.current.style.width = ringRef.current.style.height = '24px'; };
    document.querySelectorAll('a, button').forEach(el => {
      el.addEventListener('pointerenter', expand);
      el.addEventListener('pointerleave', shrink);
    });
  }, []);

  return ringRef;
}

