import { useEffect, useRef } from 'react';

export function useMagnetic(strength = 0.12, radius = 80) {
  const ref = useRef(null);

  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const onMove = (e) => {
      const r = el.getBoundingClientRect();
      const cx = r.left + r.width / 2, cy = r.top + r.height / 2;
      const dx = e.clientX - cx, dy = e.clientY - cy;
      const dist = Math.hypot(dx, dy);
      if (dist < radius) {
        const f = (radius - dist) / radius;
        el.style.transform = `translate(${dx * strength * f}px, ${dy * strength * f}px)`;
        el.style.borderColor = '#6366f1';
      } else {
        el.style.transform = '';
        el.style.borderColor = '';
      }
    };
    const onLeave = () => { el.style.transform = ''; el.style.borderColor = ''; };
    window.addEventListener('pointermove', onMove);
    el.addEventListener('pointerleave', onLeave);
    return () => {
      window.removeEventListener('pointermove', onMove);
      el.removeEventListener('pointerleave', onLeave);
    };
  }, [strength, radius]);

  return ref;
}

// Usage
export function MagneticButton({ children, ...props }) {
  const ref = useMagnetic();
  return (
    <button ref={ref} {...props}
      style={{ transition: 'transform 0.2s, border-color 0.2s', ...props.style }}>
      {children}
    </button>
  );
}

