import { useEffect, useRef } from 'react';

export function useTrail(color = 'rgba(99,102,241,', length = 22) {
  const canvasRef = useRef(null);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');
    const pts = [];
    let mx = 0, my = 0, raf;

    const resize = () => {
      canvas.width = canvas.offsetWidth * devicePixelRatio;
      canvas.height = canvas.offsetHeight * devicePixelRatio;
      ctx.setTransform(devicePixelRatio, 0, 0, devicePixelRatio, 0, 0);
    };
    resize();
    window.addEventListener('resize', resize);

    const onMove = (e) => {
      const r = canvas.getBoundingClientRect();
      mx = e.clientX - r.left; my = e.clientY - r.top;
    };
    canvas.addEventListener('pointermove', onMove);

    const loop = () => {
      pts.push({ x: mx, y: my, life: 1 });
      if (pts.length > length) pts.shift();
      ctx.clearRect(0, 0, canvas.offsetWidth, canvas.offsetHeight);
      pts.forEach(p => {
        p.life -= 0.04;
        if (p.life <= 0) return;
        ctx.beginPath();
        ctx.fillStyle = `${color}${p.life * 0.55})`;
        ctx.arc(p.x, p.y, 2 + p.life * 5, 0, Math.PI * 2);
        ctx.fill();
      });
      raf = requestAnimationFrame(loop);
    };
    loop();

    return () => {
      cancelAnimationFrame(raf);
      canvas.removeEventListener('pointermove', onMove);
      window.removeEventListener('resize', resize);
    };
  }, [color, length]);

  return canvasRef;
}

// Usage — overlay on a container
export function TrailCanvas({ style }) {
  const ref = useTrail();
  return <canvas ref={ref} style={{ position: 'absolute', inset: 0, pointerEvents: 'none', cursor: 'none', ...style }} />;
}

