import { useState, useCallback } from 'react';

type AvailState = 'available' | 'busy' | 'unavailable';

const CONFIG: Record<AvailState, { label: string; color: string; glow: string }> = {
  available:   { label: 'Available for work', color: '#10b981', glow: '0 0 0 4px rgba(16,185,129,0.2)' },
  busy:        { label: 'Busy shipping',       color: '#f59e0b', glow: 'none' },
  unavailable: { label: 'Away',               color: '#f43f5e', glow: 'none' },
};

export function useAvailability(key = 'availability') {
  const [state, setState] = useState<AvailState>(
    () => (localStorage.getItem(key) as AvailState) || 'available'
  );
  const cycle = useCallback(() => {
    const order: AvailState[] = ['available', 'busy', 'unavailable'];
    setState(prev => {
      const next = order[(order.indexOf(prev) + 1) % order.length];
      localStorage.setItem(key, next);
      return next;
    });
  }, [key]);
  return { state, cycle, ...CONFIG[state] };
}

// Usage
export function AvailabilityBadge() {
  const { label, color, glow, cycle } = useAvailability();
  return (
    <button onClick={cycle} style={{ display: 'flex', alignItems: 'center', gap: 8, background: 'none', border: 'none', cursor: 'pointer', color: 'inherit' }}>
      <span style={{ width: 10, height: 10, borderRadius: '50%', background: color, boxShadow: glow, display: 'inline-block' }} />
      <span style={{ fontWeight: 600, fontSize: 13 }}>{label}</span>
    </button>
  );
}

