import { useCallback, useRef } from 'react';

export function useWebAudio() {
  const ctxRef = useRef(null);

  const getCtx = () => {
    if (!ctxRef.current) ctxRef.current = new AudioContext();
    if (ctxRef.current.state === 'suspended') ctxRef.current.resume();
    return ctxRef.current;
  };

  const tone = useCallback((freq = 880, dur = 0.1, type = 'sine', gain = 0.05) => {
    try {
      const ctx = getCtx();
      const osc = ctx.createOscillator();
      const g = ctx.createGain();
      osc.type = type; osc.frequency.value = freq;
      g.gain.setValueAtTime(gain, ctx.currentTime);
      g.gain.exponentialRampToValueAtTime(0.001, ctx.currentTime + dur);
      osc.connect(g); g.connect(ctx.destination);
      osc.start(); osc.stop(ctx.currentTime + dur);
    } catch (_) {}
  }, []);

  return { tone };
}

// Usage — hover a link to hear a chime
export function ChimeLink({ children, freq = 1200, ...props }) {
  const { tone } = useWebAudio();
  return (
    <a onPointerEnter={() => tone(freq, 0.15, 'triangle', 0.04)} {...props}>
      {children}
    </a>
  );
}

