import { useEffect, useState, useCallback } from 'react';

export function useLoadProgress(speed = 8, interval = 180) {
  const [pct, setPct] = useState(0);
  const [done, setDone] = useState(false);

  const run = useCallback(() => {
    setPct(0); setDone(false);
    const iv = setInterval(() => {
      setPct(prev => {
        const next = Math.min(100, prev + speed + Math.random() * 12);
        if (next >= 100) { clearInterval(iv); setDone(true); }
        return next;
      });
    }, interval);
    return () => clearInterval(iv);
  }, [speed, interval]);

  useEffect(() => run(), [run]);

  return { pct, done, replay: run };
}

// Usage
export function LoadingBar({ height = 4, color = '#f8fafc' }) {
  const { pct, done } = useLoadProgress();
  if (done) return null;
  return (
    <div style={{ position: 'fixed', top: 0, left: 0, right: 0, height, background: '#334155', zIndex: 9999 }}>
      <div style={{ height: '100%', width: `${pct}%`, background: color, transition: 'width 0.2s' }} />
    </div>
  );
}

