export function useIdleEffect(idleMs = 30_000) {
  const [idle, setIdle] = useState(false);

  useEffect(() => {
    let timer;
    const reset = () => {
      setIdle(prev => prev ? false : prev); // bail-out if already active
      clearTimeout(timer);
      timer = setTimeout(() => setIdle(true), idleMs);
    };
    const events = ['pointermove', 'keydown', 'click', 'scroll'];
    events.forEach(e => window.addEventListener(e, reset, { passive: true }));
    reset();
    return () => {
      clearTimeout(timer);
      events.forEach(e => window.removeEventListener(e, reset));
    };
  }, [idleMs]);

  return idle;
}

