import { useEffect, useRef } from 'react';

export function CanvasBallpit({ count = 35 }) {
  const canvasRef = useRef(null);
  const pointerRef = useRef({ x: -999, y: -999 });

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const ctx = canvas.getContext('2d');

    let w = (canvas.width = canvas.clientWidth);
    let h = (canvas.height = canvas.clientHeight);
    let running = true;
    let rafId;

    const resize = () => {
      if (!canvas) return;
      w = canvas.width = canvas.clientWidth;
      h = canvas.height = canvas.clientHeight;
    };
    window.addEventListener('resize', resize);

    const colors = ['#818cf8', '#34d399', '#fbbf24', '#f43f5e', '#a78bfa'];
    const balls = Array.from({ length: count }, () => ({
      x: Math.random() * w,
      y: Math.random() * h,
      vx: (Math.random() - 0.5) * 1.5,
      vy: (Math.random() - 0.5) * 1.5,
      r: Math.random() * 6 + 4,
      color: colors[Math.random() * colors.length | 0],
    }));

    const handlePointerMove = (e) => {
      const rect = canvas.getBoundingClientRect();
      pointerRef.current = {
        x: e.clientX - rect.left,
        y: e.clientY - rect.top,
      };
    };

    const handlePointerLeave = () => {
      pointerRef.current = { x: -999, y: -999 };
    };

    canvas.addEventListener('pointermove', handlePointerMove);
    canvas.addEventListener('pointerleave', handlePointerLeave);

    const loop = () => {
      if (!running) return;
      ctx.clearRect(0, 0, w, h);

      const mx = pointerRef.current.x;
      const my = pointerRef.current.y;

      balls.forEach((b) => {
        b.x += b.vx;
        b.y += b.vy;

        if (b.x - b.r < 0) { b.x = b.r; b.vx *= -1; }
        if (b.x + b.r > w) { b.x = w - b.r; b.vx *= -1; }
        if (b.y - b.r < 0) { b.y = b.r; b.vy *= -1; }
        if (b.y + b.r > h) { b.y = h - b.r; b.vy *= -1; }

        if (mx !== -999 && my !== -999) {
          const dx = b.x - mx;
          const dy = b.y - my;
          const dist = Math.hypot(dx, dy);
          if (dist < 60) {
            const force = (60 - dist) / 60;
            const angle = Math.atan2(dy, dx);
            b.vx += Math.cos(angle) * force * 0.4;
            b.vy += Math.sin(angle) * force * 0.4;
          }
        }

        b.vx *= 0.98;
        b.vy *= 0.98;

        ctx.fillStyle = b.color;
        ctx.beginPath();
        ctx.arc(b.x, b.y, b.r, 0, Math.PI * 2);
        ctx.fill();
      });

      rafId = requestAnimationFrame(loop);
    };

    loop();

    return () => {
      running = false;
      cancelAnimationFrame(rafId);
      window.removeEventListener('resize', resize);
      if (canvas) {
        canvas.removeEventListener('pointermove', handlePointerMove);
        canvas.removeEventListener('pointerleave', handlePointerLeave);
      }
    };
  }, [count]);

  return <canvas ref={canvasRef} style={{ width: '100%', height: '100%', display: 'block' }} />;
}

