export function InfiniteDraggableGrid({
  items = ['React', 'CSS', 'Framer', 'ThreeJS'],
  colors = ['#818cf8', '#fbbf24', '#34d399', '#f43f5e']
}) {
  const trackRef = useRef(null);
  const [offset, setOffset] = useState(0);
  const dragRef = useRef({ isDragging: false, startX: 0 });

  const cardWidth = 80;
  const cardGap = 12;
  const pitch = cardWidth + cardGap;
  const totalWidth = items.length * pitch;

  const handlePointerDown = (e) => {
    dragRef.current = { isDragging: true, startX: e.clientX };
    trackRef.current.setPointerCapture(e.pointerId);
  };

  const handlePointerMove = (e) => {
    if (!dragRef.current.isDragging) return;
    const dx = e.clientX - dragRef.current.startX;
    dragRef.current.startX = e.clientX;
    setOffset(prev => prev + dx);
  };

  const handlePointerUp = () => {
    dragRef.current.isDragging = false;
  };

  return (
    <div
      ref={trackRef}
      onPointerDown={handlePointerDown}
      onPointerMove={handlePointerMove}
      onPointerUp={handlePointerUp}
      onPointerCancel={handlePointerUp}
      style={{
        position: 'relative',
        width: '100%',
        height: '100px',
        overflow: 'hidden',
        cursor: dragRef.current.isDragging ? 'grabbing' : 'grab',
        touchAction: 'none',
        userSelect: 'none'
      }}
    >
      {items.map((item, idx) => {
        let x = (idx * pitch + offset) % totalWidth;
        if (x < -cardWidth) x += totalWidth;
        if (x > totalWidth - cardWidth) x -= totalWidth;

        return (
          <div
            key={idx}
            style={{
              position: 'absolute',
              width: `${cardWidth}px`,
              height: '80px',
              top: '10px',
