import { useEffect, useRef, useCallback } from 'react';

const CHARS = 'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789@#$%';

export function useScramble(target = 'PROJECTS') {
  const ref = useRef(null);
  const ivRef = useRef(null);

  const run = useCallback(() => {
    clearInterval(ivRef.current);
    let i = 0;
    ivRef.current = setInterval(() => {
      if (!ref.current) return;
      ref.current.textContent = target
        .split('')
        .map((c, idx) => idx < i ? c : CHARS[Math.random() * CHARS.length | 0])
        .join('');
      if (++i > target.length) clearInterval(ivRef.current);
    }, 30);
  }, [target]);

  useEffect(() => { run(); return () => clearInterval(ivRef.current); }, [run]);

  return { ref, replay: run };
}

