import { useEffect, useRef } from 'react';

export function useTypewriter(lines = ['I build things.', 'I ship things.'], speed = 60) {
  const ref = useRef(null);

  useEffect(() => {
    let li = 0, ci = 0, del = false, t;
    const tick = () => {
      const line = lines[li];
      if (ref.current) ref.current.textContent = line.slice(0, ci) + (del ? '' : '|');
      if (!del && ci < line.length) { ci++; t = setTimeout(tick, speed); return; }
      if (!del) { t = setTimeout(() => { del = true; tick(); }, 1400); return; }
      if (ci > 0) { ci--; t = setTimeout(tick, Math.floor(speed * 0.6)); return; }
      del = false; li = (li + 1) % lines.length; t = setTimeout(tick, 280);
    };
    tick();
    return () => clearTimeout(t);
  }, []);   // intentionally [] — runs once on mount

  return ref;
}

// Usage
export function TypewriterHero() {
  const ref = useTypewriter([
    'I build things that ship.',
    'I ship things that last.',
  ]);
  return <p ref={ref} style={{ fontFamily: 'monospace', minHeight: '1.6em' }} />;
}

