import { useEffect, useRef } from 'react';

export function useCounter(target = 250, duration = 1400) {
  const ref = useRef(null);

  useEffect(() => {
    let raf;
    const start = performance.now();
    const step = (now) => {
      const progress = Math.min(1, (now - start) / duration);
      // ease-out cubic
      const ease = 1 - Math.pow(1 - progress, 3);
      if (ref.current) ref.current.textContent = Math.round(ease * target) + '+';
      if (progress < 1) raf = requestAnimationFrame(step);
    };
    raf = requestAnimationFrame(step);
    return () => cancelAnimationFrame(raf);
  }, [target, duration]);

  return ref;
}

// Usage
export function StatCounter({ value = 250 }) {
  const ref = useCounter(value);
  return (
    <span
      ref={ref}
      style={{ fontSize: 48, fontWeight: 900, fontVariantNumeric: 'tabular-nums' }}
    />
  );
}

